   203→export function trackVarReferences(
   204→  tag: t.NodePath<t.MarkoTag>,
   205→  type: BindingType,
   206→  upstreamAlias?: Binding["upstreamAlias"],
   207→) {
   208→  const tagVar = tag.node.var;
   209→  if (tagVar) {
   210→    let canonicalUpstreamAlias = getCanonicalBinding(upstreamAlias);
   211→    if (canonicalUpstreamAlias) {
   212→      const { excludeProperties } = canonicalUpstreamAlias;
   213→      if (excludeProperties !== undefined) {
   214→        canonicalUpstreamAlias = canonicalUpstreamAlias.upstreamAlias!;
   215→      }
   216→      createBindingsAndTrackReferences(
   217→        tagVar,
   218→        canonicalUpstreamAlias.type,
   219→        tag.scope,
   220→        canonicalUpstreamAlias.section,
   221→        canonicalUpstreamAlias,
   222→        undefined,
   223→        excludeProperties,
   224→      );
   225→      return canonicalUpstreamAlias;
   226→    }
   227→
   228→    createBindingsAndTrackReferences(
   229→      tagVar,
   230→      type,
   231→      tag.scope,
   232→      getOrCreateSection(tag),
   233→      undefined,
   234→      undefined,
   235→      undefined,
   236→    );
   237→    return tagVar.extra?.binding;
   238→  }
   239→}
   240→
   241→export function trackParamsReferences(
   242→  body: t.NodePath<t.MarkoTagBody | t.Program>,
   243→  type: BindingType,
   244→  upstreamAlias?: Binding["upstreamAlias"],
   245→) {
   246→  const params = body.node.params;
   247→  if (body.node.body.length && params.length) {
   248→    const canonicalUpstreamAlias = getCanonicalBinding(upstreamAlias);
   249→    let section: Section;
   250→    if (canonicalUpstreamAlias) {
   251→      section = canonicalUpstreamAlias.section;
   252→      type = canonicalUpstreamAlias.type;
   253→    } else {
   254→      section = getOrCreateSection(body);
   255→    }
   256→    const paramsBinding =
   257→      canonicalUpstreamAlias ||
   258→      ((body.node.extra ??= {}).binding = createBinding(
   259→        generateUid("params"),
   260→        type,
   261→        section,
   262→        undefined,
   263→        undefined,
   264→      ));
   265→
   266→    section.params = paramsBinding;
   267→
   268→    for (let i = 0; i < params.length; i++) {
   269→      const param = params[i];
   270→      if (param.type === "RestElement") {
   271→        createBindingsAndTrackReferences(
   272→          param.argument,
   273→          type,
   274→          body.scope,
   275→          section,
   276→          paramsBinding,
   277→          undefined,
   278→          addNumericPropertiesUntil(undefined, i - 1),
   279→        );
   280→      } else if (t.isLVal(param)) {
   281→        createBindingsAndTrackReferences(
   282→          param,
   283→          type,
   284→          body.scope,
   285→          section,
   286→          paramsBinding,
   287→          i + "",
   288→          undefined,
   289→        );
   290→      }
   291→    }
   292→
   293→    return paramsBinding;
   294→  }
   295→}
   296→
   297→export function trackHoistedReference(
   298→  referencePath: t.NodePath<t.Identifier>,
   299→  binding: Binding,
   300→) {
   301→  const section = binding.section;
   302→  const referenceSection = getOrCreateSection(referencePath);
   303→  const hoistSection = getCommonSection(referenceSection, section);
   304→  const extra = (referencePath.node.extra ??= {});
   305→
   306→  let hoistedBinding = binding.hoists.get(hoistSection);
   307→  if (!hoistedBinding) {
   308→    binding.hoists.set(
   309→      hoistSection,
   310→      (hoistedBinding = createBinding(
   311→        generateUid("hoisted_" + referencePath.node.name),
   312→        BindingType.hoist,
   313→        hoistSection,
   314→        undefined,
   315→        undefined,
   316→        undefined,
   317→        binding.loc,
   318→        true,
   319→      )),
   320→    );
   321→
   322→    section.hoisted = bindingUtil.add(section.hoisted, binding);
   323→
   324→    let currentSection = section.parent;
   325→    while (currentSection && currentSection !== hoistSection) {
   326→      currentSection.isHoistThrough = true;
   327→      currentSection = currentSection.parent;
   328→    }
   329→  }
   330→
   331→  if (isInvokedFunction(referencePath)) {
   332→    extra.read = createRead(hoistedBinding, undefined);
   333→    extra.section = referenceSection;
   334→    extra[kIsInvoked] = true;
   335→  } else {
   336→    trackReference(referencePath, hoistedBinding);
   337→  }
   338→
   339→  referenceSection.referencedHoists = bindingUtil.add(
   340→    referenceSection.referencedHoists,
   341→    hoistedBinding,
   342→  );
   343→}
   344→
   345→function trackReferencesForBinding(babelBinding: t.Binding, binding: Binding) {
   346→  const { referencePaths, constantViolations } = babelBinding;
   347→
   348→  for (const referencePath of referencePaths) {
   349→    const referenceSection = getOrCreateSection(referencePath);
   350→    if (isSameOrChildSection(binding.section, referenceSection)) {
   351→      if (
   352→        binding.type === BindingType.local &&
   353→        referenceSection === binding.section
   354→      ) {
   355→        continue;
   356→      }
   357→      trackReference(referencePath as t.NodePath<t.Identifier>, binding);
   358→    } else {
   359→      trackHoistedReference(referencePath as t.NodePath<t.Identifier>, binding);
   360→    }
   361→  }
   362→
   363→  for (const ref of constantViolations) {
   364→    if (ref.isUpdateExpression()) {
   365→      trackAssignment(ref.get("argument"), binding);
   366→    } else if (ref.isAssignmentExpression()) {
   367→      trackAssignment(ref.get("left"), binding);
   368→
   369→      if (ref.node.operator !== "=") {
   370→        /*
   371→         * https://github.com/babel/babel/issues/11313
   372→         * We need this so we can handle `+=` and friends
   373→         */
   374→        const left = ref.get("left");
   375→        if (left.isIdentifier()) {
   376→          trackReference(left, binding);
   377→        }
   378→      }
   379→    }
   380→  }
   381→}
   382→
   383→function trackAssignment(
   384→  assignment: t.NodePath<
   385→    t.AssignmentExpression["left"] | t.UpdateExpression["argument"]
   386→  >,
   387→  binding: Binding,
   388→) {
   389→  const fnRoot = getFnRoot(assignment);
   390→  const fnExtra = fnRoot && ((fnRoot.node.extra ??= {}) as FnExtra);
   391→  const section = getOrCreateSection(assignment);
   392→  setReferencesScope(assignment);
   393→  forEachIdentifierPath(assignment, (id) => {
   394→    if (id.node.name === binding.name) {
   395→      const extra = (id.node.extra ??= {}) as AssignedBindingExtra;
   396→
   397→      if (binding.upstreamAlias && binding.property !== undefined) {
   398→        const changePropName = binding.property + "Change";
   399→        const changeBinding =
   400→          binding.upstreamAlias.propertyAliases.get(changePropName) ||
   401→          createBinding(
   402→            generateUid(changePropName),
   403→            BindingType.derived,
   404→            binding.section,
   405→            binding.upstreamAlias,
   406→            changePropName,
   407→            undefined,
   408→            id.node.loc,
   409→            true,
   410→          );
   411→        extra.assignmentTo = changeBinding;
   412→        addReadToExpression(id, changeBinding);
   413→      }
   414→
   415→      binding.assignmentSections = sectionUtil.add(
   416→        binding.assignmentSections,
   417→        section,
   418→      );
   419→      extra.assignment = binding;
   420→      extra.section = section;
   421→      extra.fnExtra = fnExtra;
   422→    }
   423→  });
   424→}
   425→
   426→export function setReferencesScope(path: t.NodePath<any>) {
   427→  const fnRoot = getFnRoot(path);
   428→  if (fnRoot) {
   429→    (fnRoot.node.extra ??= {}).referencesScope = true;
   430→  }
   431→}
   432→
   433→function createBindingsAndTrackReferences(
   434→  lVal: t.LVal,
   435→  type: BindingType,
   436→  scope: t.Scope,
   437→  section: Section,
   438→  upstreamAlias: Binding["upstreamAlias"] | undefined,
   439→  property: string | undefined,
   440→  excludeProperties: Opt<string>,
   441→) {
   442→  switch (lVal.type) {
   443→    case "Identifier":
   444→      trackReferencesForBinding(
   445→        scope.getBinding(lVal.name)!,
   446→        ((lVal.extra ??= {}).binding = createBinding(
   447→          lVal.name,
   448→          type,
   449→          section,
   450→          upstreamAlias,
   451→          property,
   452→          excludeProperties,
   453→          lVal.loc,
   454→          true,
   455→        )),
   456→      );
   457→      break;
   458→    case "ObjectPattern": {
   459→      const patternBinding =
   460→        (property
   461→          ? upstreamAlias!.propertyAliases.get(property)
   462→          : upstreamAlias) ||
   463→        ((lVal.extra ??= {}).binding = createBinding(
   464→          generateUid(property || "pattern"),
   465→          type,
   466→          section,
   467→          upstreamAlias,
   468→          property,
   469→          excludeProperties,
   470→          lVal.loc,
   471→        ));
   472→
   473→      const hasRest =
   474→        lVal.properties[lVal.properties.length - 1]?.type === "RestElement";
   475→      for (const prop of lVal.properties) {
   476→        if (prop.type === "RestElement") {
   477→          createBindingsAndTrackReferences(
   478→            prop.argument,
   479→            type,
   480→            scope,
   481→            section,
   482→            patternBinding,
   483→            property,
   484→            excludeProperties,
   485→          );
   486→        } else {
   487→          let key: string;
   488→
   489→          if (prop.key.type === "Identifier") {
   490→            key = prop.key.name;
   491→          } else if (prop.key.type === "StringLiteral") {
   492→            key = prop.key.value;
   493→          } else {
   494→            // TODO: it should be a computed value
   495→            throw new Error("computed keys not supported in object pattern");
   496→          }
   497→
   498→          if (hasRest) {
   499→            excludeProperties = propsUtil.add(excludeProperties, key);
   500→          }
   501→
   502→          if (t.isLVal(prop.value)) {
   503→            createBindingsAndTrackReferences(
   504→              prop.value,
   505→              type,
   506→              scope,
   507→              section,
   508→              patternBinding,
   509→              key,
   510→              undefined,
   511→            );
   512→          }
   513→        }
   514→      }
   515→      break;
   516→    }
   517→    case "ArrayPattern": {
   518→      const patternBinding =
   519→        (property
   520→          ? upstreamAlias!.propertyAliases.get(property)
   521→          : upstreamAlias) ||
   522→        ((lVal.extra ??= {}).binding = createBinding(
   523→          generateUid(property || "pattern"),
   524→          type,
   525→          section,
   526→          upstreamAlias,
   527→          property,
   528→          excludeProperties,
   529→          lVal.loc,
   530→        ));
   531→
   532→      let i = -1;
   533→      for (const element of lVal.elements) {
   534→        i++;
   535→        if (element) {
   536→          if (element.type === "RestElement") {
   537→            excludeProperties = addNumericPropertiesUntil(
   538→              excludeProperties,
   539→              i - 1,
   540→            );
   541→            createBindingsAndTrackReferences(
   542→              element.argument,
   543→              type,
   544→              scope,
   545→              section,
   546→              patternBinding,
   547→              property,
   548→              excludeProperties,
   549→            );
   550→          } else if (t.isLVal(element)) {
   551→            createBindingsAndTrackReferences(
   552→              element,
   553→              type,
   554→              scope,
   555→              section,
   556→              patternBinding,
   557→              `${i}`,
   558→              undefined,
   559→            );
   560→          }
   561→        }
   562→      }
   563→      break;
   564→    }
   565→    case "AssignmentPattern":
   566→      // TODO: this makes a default value an alias,
   567→      // but it really should be a computed value
   568→      createBindingsAndTrackReferences(
   569→        lVal.left,
   570→        type,
   571→        scope,
   572→        section,
   573→        upstreamAlias,
   574→        property,
   575→        undefined,
   576→      );
   577→
   578→      if (lVal.left.extra?.binding) {
   579→        (lVal.right.extra ??= {}).downstream = {
   580→          bindings: lVal.left.extra.binding,
   581→          excludeProperties: undefined,
   582→        };
   583→      }
   584→      break;
   585→  }
   586→}
   587→
   588→function trackReference(
   589→  referencePath: t.NodePath<t.Identifier>,
   590→  binding: Binding,
   591→) {
   592→  let root: t.NodePath<t.Identifier> | t.NodePath<t.MemberExpression> =
   593→    referencePath;
   594→  let reference = binding;
   595→  let propPath = binding.name;
   596→
   597→  while (true) {
   598→    const { parent } = root;
   599→    if (!t.isMemberExpression(parent)) break;
   600→
   601→    const prop = getMemberExpressionPropString(parent);
   602→    if (prop === undefined) break;
   603→
   604→    if (
   605→      reference.upstreamAlias &&
   606→      reference.excludeProperties !== undefined &&
   607→      !propsUtil.has(reference.excludeProperties, prop)
   608→    ) {
   609→      reference = reference.upstreamAlias;
   610→    }
   611→
   612→    if (reference.propertyAliases.has(prop)) {
   613→      root = root.parentPath as t.NodePath<t.MemberExpression>;
   614→      reference = reference.propertyAliases.get(prop)!;
   615→      propPath = reference.name;
   616→      continue;
   617→    }
   618→
   619→    if (isInvokedFunction(root.parentPath) && !isEventOrChangeHandler(prop)) {
   620→      break;
   621→    }
   622→
   623→    root = root.parentPath as t.NodePath<t.MemberExpression>;
   624→    reference = createBinding(
   625→      (propPath += `_${prop.replace(/[^a-zA-Z0-9_$]/g, "_")}`),
   626→      reference.type,
   627→      reference.section,
   628→      reference,
   629→      prop,
   630→    );
   631→  }
   632→
   633→  addReadToExpression(root, reference);
   634→}
   635→
   636→const [getMergedReferences] = createProgramState(
   637→  () => new Map<t.Node, (t.Node | undefined)[]>(),
   638→);
   639→export function mergeReferences<T extends t.Node>(
   640→  section: Section,
   641→  target: T,
   642→  nodes: (t.Node | undefined)[],
   643→): NonNullable<T["extra"]> & ReferencedExtra {
   644→  const targetExtra = (target.extra ??= {});
   645→  targetExtra.section = section;
   646→  getMergedReferences().set(target, nodes);
   647→  return targetExtra as NonNullable<T["extra"]> & ReferencedExtra;
   648→}
   649→
   650→export function compareReferences(
   651→  a: ReferencedBindings,
   652→  b: ReferencedBindings,
   653→) {
   654→  return a === b
   655→    ? 0
   656→    : a
   657→      ? b
   658→        ? Array.isArray(a)
   659→          ? Array.isArray(b)
   660→            ? compareIntersections(a, b)
   661→            : -1
   662→          : Array.isArray(b)
   663→            ? 1
   664→            : bindingUtil.compare(a, b)
   665→        : 1
   666→      : b
   667→        ? -1
   668→        : 0;
   669→}
   670→
   671→/**
   672→ * reference group priority is sorted by number of references,
   673→ * then if needed by reference order.
   674→ */
   675→function compareIntersections(a: Intersection, b: Intersection) {
   676→  const len = a.length;
   677→  const lenDelta = len - b.length;
   678→  if (lenDelta !== 0) {
   679→    return lenDelta;
   680→  }
   681→
   682→  for (let i = 0; i < len; i++) {
   683→    const compareResult = bindingUtil.compare(a[i], b[i]);
   684→    if (compareResult !== 0) {
   685→      return compareResult;
   686→    }
   687→  }
   688→
   689→  return 0;
   690→}
   691→
   692→export function finalizeReferences() {
   693→  const bindings = getBindings();
   694→  const readsByExpression = getReadsByExpression();
   695→  const readsByFn = getReadsByFunction();
   696→  const mergedReferences = getMergedReferences();
   697→
   698→  if (mergedReferences.size) {
   699→    for (const [target, nodes] of mergedReferences) {
   700→      const targetExtra = target.extra as ReferencedExtra;
   701→      let reads = readsByExpression.get(targetExtra);
   702→      let { isEffect } = targetExtra;
   703→      for (const node of nodes) {
   704→        const extra = node?.extra;
   705→        if (extra) {
   706→          setCanonicalExtra(extra, targetExtra);
   707→          if (isReferencedExtra(extra)) {
   708→            const additionalReads = readsByExpression.get(extra);
   709→            isEffect ||= extra.isEffect;
   710→            if (additionalReads) {
   711→              reads = concat(reads, additionalReads);
   712→              readsByExpression.delete(extra);
   713→            }
   714→          }
   715→        }
   716→      }
   717→
   718→      readsByExpression.set(targetExtra, reads);
   719→      targetExtra.isEffect = isEffect;
   720→    }
   721→  }
   722→
   723→  const intersectionsBySection = new Map<Section, Intersection[]>();
   724→  for (const [expr, reads] of readsByExpression) {
   725→    if (isReferencedExtra(expr)) {
   726→      expr.referencedBindings = resolveReferencedBindings(
   727→        expr,
   728→        reads,
   729→        intersectionsBySection,
   730→      );
   731→      forEach(expr.referencedBindings, (binding) => {
   732→        binding.downstreamExpressions.add(expr);
   733→      });
   734→    }
   735→  }
   736→
   737→  for (const [fn, reads] of readsByFn) {
   738→    fn.referencedBindingsInFunction = resolveReferencedBindings(
   739→      fn,
   740→      reads,
   741→      intersectionsBySection,
   742→    );
   743→
   744→    forEach(fn.referencedBindingsInFunction, (binding) =>
   745→      forceBindingSerialize(binding.section, binding),
   746→    );
   747→  }
   748→
   749→  for (const binding of bindings) {
   750→    if (binding.type !== BindingType.dom && !binding.upstreamAlias) {
   751→      pruneBinding(bindings, binding);
   752→    }
   753→  }
   754→
   755→  for (const binding of bindings) {
   756→    const { name, section } = binding;
   757→    if (binding.type !== BindingType.dom) {
   758→      resolveBindingSources(binding);
   759→      if (binding.hoists.size) {
   760→        forceBindingSerialize(binding.section, binding);
   761→      }
   762→
   763→      forEach(binding.assignmentSections, (assignedSection) =>
   764→        forceOwnersSerialize(assignedSection, section, getAccessorProp().Owner),
   765→      );
   766→
   767→      if (find(section.bindings, ({ name }) => name === binding.name)) {
   768→        /*
   769→          TODO: this will break if parent sections use the generated UID.
   770→          ```
   771→          let/_count
   772→          my-tag
   773→            let/count
   774→            div
   775→              let/count
   776→              -- ${_count}
   777→          ```
   778→        */
   779→        binding.name = generateUid(name);
   780→      }
   781→    }
   782→
   783→    section.bindings = bindingUtil.add(section.bindings, binding);
   784→    for (const {
   785→      referencedBindings,
   786→      isEffect,
   787→      section,
   788→    } of binding.downstreamExpressions) {
   789→      if (section !== binding.section) {
   790→        const canonicalUpstreamAlias = getCanonicalBinding(binding)!;
   791→        canonicalUpstreamAlias.closureSections = sectionUtil.add(
   792→          canonicalUpstreamAlias.closureSections,
   793→          section,
   794→        );
   795→
   796→        if (binding.type === BindingType.local) {
   797→          section.referencedLocalClosures = bindingUtil.add(
   798→            section.referencedLocalClosures,
   799→            binding,
   800→          );
   801→        } else {
   802→          section.referencedClosures = bindingUtil.add(
   803→            section.referencedClosures,
   804→            binding,
   805→          );
   806→
   807→          addOwnersSerializeReason(
   808→            section,
   809→            canonicalUpstreamAlias.section,
   810→            !!isEffect || canonicalUpstreamAlias.sources,
   811→            getAccessorProp().Owner,
   812→          );
   813→        }
   814→      }
   815→      if (isEffect) {
   816→        forEach(referencedBindings, (binding) =>
   817→          forceBindingSerialize(binding.section, binding),
   818→        );
   819→      }
   820→    }
   821→  }
   822→
   823→  forEachSection((section) => {
   824→    if (section.isHoistThrough) {
   825→      forceSectionSerialize(section);
   826→    }
   827→
   828→    forEach(section.referencedHoists, (hoistedBinding) => {
   829→      forceOwnersSerialize(
   830→        section,
   831→        hoistedBinding.section,
   832→        getAccessorProp().Owner,
   833→      );
   834→    });
   835→
   836→    if (
   837→      section.parent &&
   838→      section.isBranch &&
   839→      section.sectionAccessor &&
   840→      section.upstreamExpression
   841→    ) {
   842→      addSectionSerializeReasonRef(
   843→        section,
   844→        !!(section.isHoistThrough || section.hoisted) ||
   845→          getDirectClosures(section),
   846→        kBranchSerializeReason,
   847→      );
   848→      addSectionSerializeReasonExpr(
   849→        section,
   850→        section.upstreamExpression,
   851→        kBranchSerializeReason,
   852→      );
   853→      addBindingSerializeReasonExpr(
   854→        section.parent,
   855→        section.sectionAccessor.binding,
   856→        section.upstreamExpression,
   857→      );
   858→    }
   859→  });
   860→
   861→  forEachSection(applySerializeReasonExprs);
   862→
   863→  forEachSection((section) => {
   864→    const intersections = intersectionsBySection.get(section);
   865→    if (intersections) {
   866→      // mark bindings that need to be serialized due to being in an intersection with state
   867→      for (const intersection of intersections) {
   868→        const numReferences = intersection.length;
   869→        // TODO: in some cases we should be able to short circuit this
   870→        // if we know that the references are already serialized
   871→        for (let i = 0; i < numReferences - 1; i++) {
   872→          for (let j = i + 1; j < numReferences; j++) {
   873→            const binding1 = intersection[i];
   874→            const binding2 = intersection[j];
   875→            if (
   876→              !isBindingForceSerialized(section, binding1) &&
   877→              !isSupersetSources(binding1, binding2)
   878→            ) {
   879→              if (!isSameOrChildSection(section, binding1.section)) {
   880→                addOwnersSerializeReason(
   881→                  section,
   882→                  binding1.section,
   883→                  mergeSerializeReasons(
   884→                    // TODO should check for an actual intersection, not just stateful
   885→                    binding1.sources,
   886→                    binding2.sources,
   887→                  ),
   888→                  getAccessorProp().Owner,
   889→                );
   890→              }
   891→
   892→              addBindingSerializeReason(
   893→                binding1.section,
   894→                binding1,
   895→                binding2.sources, // TODO should check for an actual intersection, not just binding2.sources stateful
   896→              );
   897→            }
   898→            if (
   899→              !isBindingForceSerialized(section, binding2) &&
   900→              !isSupersetSources(binding2, binding1)
   901→            ) {
   902→              if (!isSameOrChildSection(section, binding2.section)) {
   903→                addOwnersSerializeReason(
   904→                  section,
   905→                  binding2.section,
   906→                  mergeSerializeReasons(
   907→                    // TODO should check for an actual intersection, not just stateful
   908→                    binding1.sources,
   909→                    binding2.sources,
   910→                  ),
   911→                  getAccessorProp().Owner,
   912→                );
   913→              }
   914→              addBindingSerializeReason(
   915→                binding2.section,
   916→                binding2,
   917→                binding1.sources, // TODO should check for an actual intersection, not just binding1.sources stateful
   918→              );
   919→            }
   920→          }
   921→        }
   922→      }
   923→    }
   924→
   925→    forEach(section.referencedLocalClosures, (closure) => {
   926→      // mark bindings that need to be serialized due to being closed over by stateful sections
   927→      if (!isBindingForceSerialized(section, closure)) {
   928→        const sourceSection = closure.section;
   929→        let serializeReason: undefined | SerializeReason;
   930→        let currentSection = section;
   931→
   932→        while (currentSection !== sourceSection) {
   933→          const upstreamReason = currentSection.downstreamBinding
   934→            ? isSerializedSection(currentSection) || undefined
   935→            : !currentSection.upstreamExpression ||
   936→              getSerializeSourcesForExpr(currentSection.upstreamExpression);
   937→          if (upstreamReason === true) {
   938→            serializeReason = true;
   939→            break;
   940→          }
   941→
   942→          serializeReason = mergeSerializeReasons(
   943→            serializeReason,
   944→            upstreamReason,
   945→          );
   946→          currentSection = currentSection.parent!;
   947→        }
   948→
   949→        addBindingSerializeReason(section, closure, serializeReason);
   950→      }
   951→
   952→      if (closure.sources) {
   953→        addSectionSerializeReason(
   954→          section,
   955→          getBindingSerializeReason(section, closure),
   956→        );
   957→      }
   958→    });
   959→
   960→    forEach(section.referencedClosures, (closure) => {
   961→      // mark bindings that need to be serialized due to being closed over by stateful sections
   962→      if (!isBindingForceSerialized(closure.section, closure)) {
   963→        const sourceSection = closure.section;
   964→        let serializeReason: undefined | SerializeReason;
   965→        let currentSection = section;
   966→
   967→        while (currentSection !== sourceSection) {
   968→          const upstreamReason = currentSection.downstreamBinding
   969→            ? isSerializedSection(currentSection) || undefined
   970→            : !currentSection.upstreamExpression ||
   971→              getSerializeSourcesForExpr(currentSection.upstreamExpression);
   972→          if (upstreamReason === true) {
   973→            serializeReason = true;
   974→            break;
   975→          }
   976→
   977→          serializeReason = mergeSerializeReasons(
   978→            serializeReason,
   979→            upstreamReason,
   980→          );
   981→          currentSection = currentSection.parent!;
   982→        }
   983→
   984→        addBindingSerializeReason(closure.section, closure, serializeReason);
   985→      }
   986→
   987→      if (closure.sources) {
   988→        addSectionSerializeReason(
   989→          closure.section,
   990→          getBindingSerializeReason(closure.section, closure),
   991→        );
   992→      }
   993→
   994→      if (closure.sources && isDynamicClosure(section, closure)) {
   995→        addBindingSerializeReason(
   996→          closure.section,
   997→          closure,
   998→          closure.sources,
   999→          getAccessorPrefix().ClosureScopes,
  1000→        );
  1001→        addBindingSerializeReason(
  1002→          section,
  1003→          closure,
  1004→          closure.sources,
  1005→          getAccessorPrefix().ClosureSignalIndex,
  1006→        );
  1007→      }
  1008→    });
  1009→  });
  1010→
  1011→  let inputSerializeReasons: undefined | InputSerializeReasons;
  1012→  forEachSection((section) => {
  1013→    finalizeSectionSerializeReasons(section);
  1014→
  1015→    if (
  1016→      section.serializeReason &&
  1017→      section.serializeReason !== true &&
  1018→      section.serializeReason.input
  1019→    ) {
  1020→      inputSerializeReasons = inputSerializeReasons
  1021→        ? addSorted(
  1022→            compareReferences,
  1023→            inputSerializeReasons,
  1024→            section.serializeReason.input,
  1025→          )
  1026→        : [section.serializeReason.input];
  1027→    }
  1028→
  1029→    for (const [, reason] of section.serializeReasons) {
  1030→      if (reason !== true && reason.input) {
  1031→        inputSerializeReasons = inputSerializeReasons
  1032→          ? addSorted(compareReferences, inputSerializeReasons, reason.input)
  1033→          : [reason.input];
  1034→      }
  1035→    }
  1036→  });
  1037→
  1038→  const programExtra = getProgram().node.extra;
  1039→  if (programExtra.returnValueExpr) {
  1040→    const returnSources = getSerializeSourcesForExpr(
  1041→      programExtra.returnValueExpr,
  1042→    );
  1043→    if (returnSources) {
  1044→      programExtra.returnSerializeReason = returnSources.state
  1045→        ? true
  1046→        : returnSources.input;
  1047→    }
  1048→  }
  1049→  programExtra.inputSerializeReasons = inputSerializeReasons;
  1050→
  1051→  forEachSection((section) => {
  1052→    let intersectionIndex = 0;
  1053→    const intersections = intersectionsBySection.get(section) || [];
  1054→    const { id, bindings } = section;
  1055→    const isOwnedBinding = ({ section }: Binding) => section.id === id;
  1056→    let lastBindingIndex = 0;
  1057→    let intersection: Intersection;
  1058→    forEach(filter(bindings, isOwnedBinding), (binding, bindingIndex) => {
  1059→      binding.id = (lastBindingIndex = bindingIndex) + intersectionIndex;
  1060→      while (
  1061→        intersectionIndex < intersections.length &&
  1062→        (intersection = intersections[intersectionIndex])
  1063→          .filter(isOwnedBinding)
  1064→          .at(-1) === binding
  1065→      ) {
  1066→        intersectionMeta.set(intersection, {
  1067→          id: bindingIndex + ++intersectionIndex,
  1068→          scopeOffset: getMaxOwnSourceOffset(intersection, section),
  1069→        });
  1070→      }
  1071→    });
  1072→
  1073→    while (intersectionIndex < intersections.length) {
  1074→      intersection = intersections[intersectionIndex];
  1075→      intersectionMeta.set(intersection, {
  1076→        id: lastBindingIndex + ++intersectionIndex,
  1077→        scopeOffset: getMaxOwnSourceOffset(intersection, section),
  1078→      });
  1079→    }
  1080→  });
  1081→
  1082→  finalizeFunctionRegistry();
  1083→  mergedReferences.clear();
  1084→  readsByExpression.clear();
  1085→  readsByFn.clear();
  1086→}
  1087→
  1088→function getMaxOwnSourceOffset(intersection: Intersection, section: Section) {
  1089→  let scopeOffset: Binding | undefined;
  1090→
  1091→  for (const binding of intersection) {
  1092→    if (binding.section === section && binding.sources) {
  1093→      const trackScopeOffset = (source: Binding) => {
  1094→        if (
  1095→          source.scopeOffset &&
  1096→          (!scopeOffset || scopeOffset.id < source.scopeOffset.id)
  1097→        ) {
  1098→          scopeOffset = source.scopeOffset;
  1099→        }
  1100→      };
  1101→      forEach(binding.sources.state, trackScopeOffset);
  1102→      forEach(binding.sources.input, trackScopeOffset);
  1103→    }
  1104→  }
  1105→
  1106→  return scopeOffset;
  1107→}
  1108→
  1109→export const intersectionMeta = new WeakMap<
  1110→  Intersection,
  1111→  { id: number; scopeOffset: Binding | undefined }
  1112→>();
  1113→
  1114→export function setBindingValueExpr(
  1115→  binding: Binding,
  1116→  valueExpr: boolean | Opt<t.NodeExtra>,
  1117→) {
  1118→  bindingValueExprs.set(binding, valueExpr || false);
  1119→}
  1120→
  1121→const resolvedSources = new WeakSet<Binding>();
  1122→const bindingValueExprs = new WeakMap<Binding, boolean | Opt<t.NodeExtra>>();
  1123→function resolveBindingSources(binding: Binding) {
  1124→  if (resolvedSources.has(binding)) return;
  1125→  resolvedSources.add(binding);
  1126→
  1127→  switch (binding.type) {
  1128→    case BindingType.let:
  1129→      binding.sources = createSources(binding, undefined);
  1130→      return;
  1131→    case BindingType.input:
  1132→      binding.sources = createSources(undefined, binding as InputBinding);
  1133→      return;
  1134→  }
  1135→
  1136→  if (binding.upstreamAlias) {
  1137→    let alias: Binding | undefined;
  1138→    let source = binding;
  1139→    while ((alias = source.upstreamAlias)) {
  1140→      source = alias;
  1141→    }
  1142→
  1143→    if (!resolvedSources.has(source)) {
  1144→      resolvedSources.add(source);
  1145→      resolveDerivedSources(source);
  1146→    }
  1147→
  1148→    binding.sources = source.sources;
  1149→  } else {
  1150→    resolveDerivedSources(binding);
  1151→  }
  1152→}
  1153→
  1154→function resolveDerivedSources(binding: Binding) {
  1155→  const exprs = bindingValueExprs.get(binding);
  1156→  bindingValueExprs.delete(binding);
  1157→
  1158→  if (exprs === undefined || exprs === true) {
  1159→    binding.sources = createSources(binding, undefined);
  1160→  } else if (exprs) {
  1161→    const seen = new Set<Binding>();
  1162→    forEach(exprs, (expr) => {
  1163→      if (isReferencedExtra(expr)) {
  1164→        forEach(expr.referencedBindings, (ref) => {
  1165→          if (!seen.has(ref)) {
  1166→            seen.add(ref);
  1167→            resolveBindingSources(ref);
  1168→            binding.sources = mergeSources(binding.sources, ref.sources);
  1169→          }
  1170→        });
  1171→      }
  1172→    });
  1173→  }
  1174→}
  1175→
  1176→export function createSources(
  1177→  state: Sources["state"],
  1178→  input: Sources["input"],
  1179→): Sources {
  1180→  if (!(state || input)) {
  1181→    throw new Error(
  1182→      "Cannot create a serialize reason that does not reference state or input.",
  1183→    );
  1184→  }
  1185→
  1186→  return { state, input } as Sources;
  1187→}
  1188→
  1189→export function compareSources(a: Sources, b: Sources) {
  1190→  let delta = 0;
  1191→
  1192→  if (a.input) {
  1193→    if (!b.input) return 1;
  1194→    if ((delta = compareReferences(a.input, b.input))) return delta;
  1195→  } else if (b.input) {
  1196→    return -1;
  1197→  }
  1198→
  1199→  if (a.state) {
  1200→    if (!b.state) return 1;
  1201→    if ((delta = compareReferences(a.state, b.state))) return delta;
  1202→  } else if (b.state) {
  1203→    return -1;
  1204→  }
  1205→
  1206→  return 0;
  1207→}
  1208→
  1209→export function mergeSources(a: undefined | Sources, b: undefined | Sources) {
  1210→  if (!a) return b;
  1211→  if (!b) return a;
  1212→  if (a.state === b.state && a.input === b.input) return a;
  1213→  return createSources(
  1214→    bindingUtil.union(a.state, b.state),
  1215→    bindingUtil.union(a.input, b.input),
  1216→  );
  1217→}
  1218→
  1219→export const bindingUtil = new Sorted(function compareBindings(
  1220→  a: Binding,
  1221→  b: Binding,
  1222→) {
  1223→  return a === b
  1224→    ? 0
  1225→    : a.section.id - b.section.id ||
  1226→        (a.type !== b.type &&
  1227→          (a.type === BindingType.dom || b.type === BindingType.dom))
  1228→      ? a.type - b.type || a.id - b.id
  1229→      : a.id - b.id;
  1230→});
  1231→
  1232→const propsUtil = new Sorted(function compareProps(a: string, b: string) {
  1233→  return a < b ? -1 : a > b ? 1 : 0;
  1234→});
  1235→
  1236→const [getReadsByExpression] = createProgramState(
  1237→  () => new Map<ReferencedExtra, Opt<Read>>(),
  1238→);
  1239→const [getReadsByFunction] = createProgramState(
  1240→  () => new Map<FnExtra, Opt<Read>>(),
  1241→);
  1242→
  1243→function addReadToExpression(
  1244→  root: t.NodePath<t.Identifier> | t.NodePath<t.MemberExpression>,
  1245→  binding: Binding,
  1246→) {
  1247→  const { node } = root;
  1248→  const fnRoot = getFnRoot(root);
  1249→  const exprRoot = getExprRoot(fnRoot || root);
  1250→  const exprExtra = (exprRoot.node.extra ??= {}) as ReferencedExtra;
  1251→  const readsByExpression = getReadsByExpression();
  1252→  const section = (exprExtra.section = getOrCreateSection(exprRoot));
  1253→  const read: Read = { binding, node };
  1254→  readsByExpression.set(
  1255→    exprExtra,
  1256→    push(readsByExpression.get(exprExtra), read),
  1257→  );
  1258→
  1259→  if (fnRoot) {
  1260→    const readsByFn = getReadsByFunction();
  1261→    const fnExtra = (fnRoot.node.extra ??= {}) as FnExtra;
  1262→    exprExtra.fnExtra = fnExtra;
  1263→    fnExtra.section = section;
  1264→    readsByFn.set(fnExtra, push(readsByFn.get(fnExtra), read));
  1265→  }
  1266→}
  1267→
  1268→export function dropReferences(node: t.Node | t.Node[]) {
  1269→  if (Array.isArray(node)) {
  1270→    for (const item of node) {
  1271→      (item.extra ??= {}).pruned = true;
  1272→    }
  1273→  } else {
  1274→    (node.extra ??= {}).pruned = true;
  1275→  }
  1276→}
  1277→
  1278→export function getCanonicalBinding(binding?: Binding) {
  1279→  const alias = binding?.upstreamAlias;
  1280→  if (
  1281→    alias &&
  1282→    binding.property === undefined &&
  1283→    binding.excludeProperties === undefined
  1284→  ) {
  1285→    return alias;
  1286→  }
  1287→
  1288→  return binding;
  1289→}
  1290→
  1291→export function getAllTagReferenceNodes(
  1292→  tag: t.MarkoTag,
  1293→  referenceNodes: t.Node[] = [],
  1294→) {
  1295→  if (tag.arguments) {
  1296→    for (const arg of tag.arguments) {
  1297→      referenceNodes.push(arg);
  1298→    }
  1299→  }
  1300→
  1301→  for (const attr of tag.attributes) {
  1302→    referenceNodes.push(attr.value);
  1303→  }
  1304→
  1305→  for (const child of tag.body.attributeTags
  1306→    ? tag.body.body
  1307→    : tag.attributeTags) {
  1308→    switch (child.type) {
  1309→      case "MarkoTag":
  1310→        getAllTagReferenceNodes(child, referenceNodes);
  1311→        break;
  1312→      case "MarkoScriptlet":
  1313→        for (const statement of child.body) {
  1314→          referenceNodes.push(statement);
  1315→        }
  1316→        break;
  1317→    }
  1318→  }
  1319→
  1320→  return referenceNodes;
  1321→}
  1322→
  1323→export function getScopeAccessorLiteral(binding: Binding, includeId?: boolean) {
  1324→  const canonicalBinding = getCanonicalBinding(binding)!;
  1325→  if (isOptimize()) {
  1326→    return t.numericLiteral(canonicalBinding.id);
  1327→  }
  1328→
  1329→  return t.stringLiteral(
  1330→    canonicalBinding.name +
  1331→      (includeId || canonicalBinding.type === BindingType.dom
  1332→        ? `/${canonicalBinding.id}`
  1333→        : ""),
  1334→  );
  1335→}
  1336→
  1337→export function getScopeAccessor(binding: Binding, includeId?: boolean) {
  1338→  const canonicalBinding = getCanonicalBinding(binding)!;
  1339→  if (isOptimize()) {
  1340→    return canonicalBinding.id + "";
  1341→  }
  1342→
  1343→  return (
  1344→    canonicalBinding.name +
  1345→    (includeId || canonicalBinding.type === BindingType.dom
  1346→      ? `/${canonicalBinding.id}`
  1347→      : "")
  1348→  );
  1349→}
  1350→
  1351→export function getDebugScopeAccess(binding: Binding) {
  1352→  let root = binding;
  1353→  let access = "";
  1354→  while (
  1355→    !(root.loc || root.declared) &&
  1356→    root.upstreamAlias &&
  1357→    root.excludeProperties === undefined
  1358→  ) {
  1359→    if (root.property !== undefined) {
  1360→      access = toAccess(root.property) + access;
  1361→    }
  1362→    root = root.upstreamAlias;
  1363→  }
  1364→
  1365→  return {
  1366→    root,
  1367→    access,
  1368→  };
  1369→}
  1370→
  1371→export function getDebugName(binding: Binding) {
  1372→  const { root, access } = getDebugScopeAccess(binding);
  1373→  return root.name + access;
  1374→}
  1375→
  1376→export function getInputDebugName(binding: InputBinding) {
  1377→  let root = binding;
  1378→  let access = "";
  1379→  while (root.upstreamAlias !== root.section.params) {
  1380→    if (root.property !== undefined) {
  1381→      access = toAccess(root.property) + access;
  1382→    }
  1383→    root = root.upstreamAlias as InputBinding;
  1384→  }
  1385→
  1386→  return root.name + access;
  1387→}
  1388→
  1389→export function getSectionInstancesAccessor(section: Section) {
  1390→  return section.sectionAccessor
  1391→    ? section.sectionAccessor.prefix +
  1392→        getScopeAccessor(section.sectionAccessor.binding)
  1393→    : getAccessorPrefix().ClosureScopes + section.id;
  1394→}
  1395→
  1396→export function getSectionInstancesAccessorLiteral(section: Section) {
  1397→  const accessor = getSectionInstancesAccessor(section);
  1398→  return accessor
  1399→    ? typeof accessor === "number"
  1400→      ? t.numericLiteral(accessor)
  1401→      : t.stringLiteral(accessor)
  1402→    : undefined;
  1403→}
  1404→
  1405→export function getReadReplacement(node: t.Identifier | t.MemberExpression) {
  1406→  const { extra } = node;
  1407→  if (!extra) return;
  1408→  let { binding, read } = extra;
  1409→  let replacement: t.Node | undefined;
  1410→
  1411→  if (read) {
  1412→    if (read.props === undefined) {
  1413→      binding = read.binding;
  1414→      read = undefined;
  1415→    } else {
  1416→      binding = undefined;
  1417→    }
  1418→  }
  1419→
  1420→  if (binding) {
  1421→    if (node.type === "Identifier") {
  1422→      if (binding.type === BindingType.hoist) {
  1423→        replacement = node.extra?.[kIsInvoked]
  1424→          ? t.callExpression(getHoistFunctionIdentifier(binding), [
  1425→              getScopeExpression(node.extra.section!, binding.section),
  1426→            ])
  1427→          : t.identifier(getScopeAccessor(binding)!);
  1428→      } else if (binding.name !== node.name) {
  1429→        node.name = binding.name;
  1430→      }
  1431→    } else {
  1432→      replacement = t.identifier(binding.name);
  1433→    }
  1434→  } else if (read) {
  1435→    replacement = toMemberExpression(
  1436→      t.identifier(read.binding.name),
  1437→      Array.isArray(read.props) ? read.props[0] : read.props!,
  1438→    );
  1439→
  1440→    if (Array.isArray(read.props)) {
  1441→      for (let i = 1; i < read.props.length; i++) {
  1442→        replacement = toMemberExpression(replacement, read.props[i]);
  1443→      }
  1444→    }
  1445→  }
  1446→
  1447→  return replacement && withPreviousLocation(replacement, node);
  1448→}
  1449→
  1450→function pruneBinding(bindings: Set<Binding>, binding: Binding) {
  1451→  let shouldPrune = !binding.downstreamExpressions.size;
  1452→
  1453→  if (binding.hoists.size) {
  1454→    // TODO hoists do not currently know their downstream expressions and so cannot be pruned like aliases.
  1455→    shouldPrune = false;
  1456→    // for (const [hoistSection, hoistAlias] of binding.hoists) {
  1457→    //   if (pruneBinding(bindings, hoistAlias)) {
  1458→    //     binding.hoists.delete(hoistSection);
  1459→    //   } else {
  1460→    //     shouldPrune = false;
  1461→    //   }
  1462→    // }
  1463→  }
  1464→
  1465→  for (const alias of binding.aliases) {
  1466→    if (pruneBinding(bindings, alias)) {
  1467→      binding.aliases.delete(alias);
  1468→    } else {
  1469→      shouldPrune = false;
  1470→    }
  1471→  }
  1472→
  1473→  for (const [key, alias] of binding.propertyAliases) {
  1474→    if (pruneBinding(bindings, alias)) {
  1475→      binding.propertyAliases.delete(key);
  1476→    } else {
  1477→      shouldPrune = false;
  1478→    }
  1479→  }
  1480→
  1481→  if (shouldPrune) {
  1482→    bindings.delete(binding);
  1483→  }
  1484→
  1485→  return shouldPrune;
  1486→}
  1487→
  1488→function resolveReferencedBindings(
  1489→  expr: { section: Section },
  1490→  reads: Opt<Read>,
  1491→  intersectionsBySection: Map<Section, Intersection[]>,
  1492→) {
  1493→  let referencedBindings: ReferencedBindings;
  1494→  if (Array.isArray(reads)) {
  1495→    for (const read of reads) {
  1496→      let { binding } = read;
  1497→      if (read.node) {
  1498→        const exprReference = ((read.node.extra ??= {}).read ??=
  1499→          resolveExpressionReference(reads, binding, undefined));
  1500→        ({ binding } = (read.node.extra ??= {}).read = exprReference);
  1501→      }
  1502→
  1503→      referencedBindings = bindingUtil.add(referencedBindings, binding);
  1504→    }
  1505→  } else if (reads) {
  1506→    if (reads.node) {
  1507→      (reads.node.extra ??= {}).read = createRead(reads.binding, undefined);
  1508→    }
  1509→    referencedBindings = reads.binding;
  1510→  }
  1511→
  1512→  if (Array.isArray(referencedBindings)) {
  1513→    // Resolve canonical intersection based on the expressions section.
  1514→    // This ensures referential equality between reference binding groups.
  1515→    const intersections = intersectionsBySection.get(expr.section) || [];
  1516→    const intersection = findSorted(
  1517→      compareIntersections,
  1518→      intersections,
  1519→      referencedBindings,
  1520→    );
  1521→    if (intersection) {
  1522→      referencedBindings = intersection;
  1523→    } else {
  1524→      intersectionsBySection.set(
  1525→        expr.section,
  1526→        addSorted(compareIntersections, intersections, referencedBindings),
  1527→      );
  1528→    }
  1529→  }
  1530→  return referencedBindings;
  1531→}
  1532→
  1533→function resolveExpressionReference(
  1534→  reads: Opt<Read>,
  1535→  readBinding: Binding,
  1536→  readProps: Opt<string>,
  1537→) {
  1538→  const { upstreamAlias } = readBinding;
  1539→  if (upstreamAlias && Array.isArray(reads)) {
  1540→    const prop = getCanonicalProperty(readBinding);
  1541→    const aliasProps = prop === undefined ? readProps : push(readProps, prop);
  1542→    for (const { binding } of reads) {
  1543→      if (binding !== readBinding) {
  1544→        let alias = upstreamAlias;
  1545→
  1546→        while (alias) {
  1547→          if (binding === alias) {
  1548→            return resolveExpressionReference(reads, alias, aliasProps);
  1549→          }
  1550→
  1551→          alias = alias.upstreamAlias!;
  1552→        }
  1553→      }
  1554→    }
  1555→  }
  1556→
  1557→  return createRead(readBinding, readProps);
  1558→}
  1559→
  1560→function isSupersetSources(a: Binding, b: Binding) {
  1561→  if (!b.sources) return true;
  1562→  if (!a.sources) return false;
  1563→  return (
  1564→    bindingUtil.isSuperset(a.sources.state, b.sources.state) &&
  1565→    bindingUtil.isSuperset(a.sources.input, b.sources.input)
  1566→  );
  1567→}
  1568→
  1569→function getCanonicalProperty(binding: Binding) {
  1570→  if (binding.property !== undefined) {
  1571→    return binding.property;
  1572→  }
  1573→
  1574→  if (binding.upstreamAlias && binding.excludeProperties === undefined) {
  1575→    return binding.upstreamAlias.property;
  1576→  }
  1577→}
  1578→
  1579→function createRead(binding: Binding, props: Opt<string>) {
  1580→  return { binding, props };
  1581→}
  1582→
  1583→function getMemberExpressionPropString(expr: t.MemberExpression) {
  1584→  switch (expr.property.type) {
  1585→    case "StringLiteral":
  1586→      return expr.property.value;
  1587→    case "NumericLiteral":
  1588→      return "" + expr.property.value;
  1589→    case "Identifier":
  1590→      if (expr.computed) return;
  1591→      return expr.property.name;
  1592→  }
  1593→}
  1594→
  1595→function isEventOrChangeHandler(prop: string) {
  1596→  return /^on[-A-Z][a-zA-Z0-9_$]|[a-zA-Z_$][a-zA-Z0-9_$]*Change$/.test(prop);
  1597→}
  1598→
  1599→export interface ReferencedExtra extends t.NodeExtra {
  1600→  section: Section;
  1601→  fnExtra?: FnExtra;
  1602→}
  1603→export function isReferencedExtra(
  1604→  extra: t.NodeExtra | undefined,
  1605→): extra is ReferencedExtra {
  1606→  return !!(extra && !extra.pruned && extra.section);
  1607→}
  1608→
  1609→export interface AssignedBindingExtra extends ReferencedExtra {
  1610→  assignment: Binding;
  1611→}
  1612→export function isAssignedBindingExtra(
  1613→  extra: t.NodeExtra | undefined,
  1614→): extra is AssignedBindingExtra {
  1615→  return isReferencedExtra(extra) && extra.assignment !== undefined;
  1616→}
  1617→
  1618→export interface RegisteredFnExtra extends ReferencedExtra {
  1619→  registerId: string;
  1620→  name: string;
  1621→  referencesScope?: boolean;
  1622→  referencedBindingsInFunction: ReferencedBindings;
  1623→}
  1624→export function isRegisteredFnExtra(
  1625→  extra: t.NodeExtra | undefined,
  1626→): extra is RegisteredFnExtra {
  1627→  return isReferencedExtra(extra) && extra.registerId !== undefined;
  1628→}
  1629→
  1630→export function getCanonicalExtra<T extends t.NodeExtra>(extra: T): T {
  1631→  while (extra.merged) {
  1632    extra = extra.merged as T;
  1633→  }
  1634→
  1635→  return extra;
  1636→}
  1637→
  1638→function setCanonicalExtra(extra: t.NodeExtra, merged: t.NodeExtra) {
  1639→  extra.merged = merged;
  1640→}
  1641→
  1642→function addNumericPropertiesUntil(props: Opt<string>, len: number) {
  1643→  let result = props;
  1644→  for (let i = len; i--; ) {
  1645→    result = propsUtil.add(result, i + "");
  1646→  }
  1647→  return result;
  1648→}
